mapper.select:
SELECT c.id, c.user_id, c.name, c.type, c.parent_id, c.icon, c.sort_order, c.is_deleted, c.created_at, MAX(t.created_at) as last_used FROM category c INNER JOIN entry e ON e.account_id = c.id AND e.account_type = 'category' INNER JOIN `transaction` t ON t.id = e.transaction_id AND t.is_deleted = 0 WHERE (c.user_id IS NULL OR c.user_id = #{userId})
AND c.type = #{type}
AND c.is_deleted = 0 AND c.id NOT IN (SELECT ref_id FROM user_data_hide WHERE user_id = #{userId} AND data_type = 'category') GROUP BY c.id, c.user_id, c.name, c.type, c.parent_id, c.icon, c.sort_order, c.is_deleted, c.created_at ORDER BY last_used DESC LIMIT #{limit}
